//   - pending: アップロード済み、未処理
//   - processing: AI 解析中
//   - completed: 解析・落書き生成完了
//   - failed: 解析失敗
//
// Ref: #/components/schemas/ProcessingStatus
type ProcessingStatus string

const (
	ProcessingStatusPending    ProcessingStatus = "pending"
	ProcessingStatusProcessing ProcessingStatus = "processing"
	ProcessingStatusCompleted  ProcessingStatus = "completed"
	ProcessingStatusFailed     ProcessingStatus = "failed"
)

// AllValues returns all ProcessingStatus values.
func (ProcessingStatus) AllValues() []ProcessingStatus {
	return []ProcessingStatus{
		ProcessingStatusPending,
		ProcessingStatusProcessing,
		ProcessingStatusCompleted,
		ProcessingStatusFailed,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s ProcessingStatus) MarshalText() ([]byte, error) {
	switch s {
	case ProcessingStatusPending:
		return []byte(s), nil
	case ProcessingStatusProcessing:
		return []byte(s), nil
	case ProcessingStatusCompleted:
		return []byte(s), nil
	case ProcessingStatusFailed:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *ProcessingStatus) UnmarshalText(data []byte) error {
	switch ProcessingStatus(data) {
	case ProcessingStatusPending:
		*s = ProcessingStatusPending
		return nil
	case ProcessingStatusProcessing:
		*s = ProcessingStatusProcessing
		return nil
	case ProcessingStatusCompleted:
		*s = ProcessingStatusCompleted
		return nil
	case ProcessingStatusFailed:
		*s = ProcessingStatusFailed
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

